// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "fhevm/lib/TFHE.sol";
import "fhevm/config/ZamaFHEVMConfig.sol";
import "fhevm-contracts/contracts/token/ERC20/extensions/ConfidentialERC20Mintable.sol";

contract MockUSDC is SepoliaZamaFHEVMConfig, ConfidentialERC20Mintable {
    constructor() ConfidentialERC20Mintable("Mock USDC", "mUSDC", msg.sender) {}

    /**
     * @dev Override to handle zero-initialized (unset) balances.
     * On Sepolia, TFHE.add(uninitializedHandle, amount) reverts because handle 0
     * is not registered in the ACL. We must trivialEncrypt(0) first if the balance
     * has never been set.
     */
    function _unsafeMintNoEvent(
        address account,
        uint64 amount
    ) internal override {
        euint64 currentBalance = _balances[account];
        euint64 newBalance;

        if (!TFHE.isInitialized(currentBalance)) {
            // First mint for this account — start from encrypted zero
            newBalance = TFHE.asEuint64(amount);
        } else {
            newBalance = TFHE.add(currentBalance, amount);
        }

        _balances[account] = newBalance;
        TFHE.allowThis(newBalance);
        TFHE.allow(newBalance, account);
    }
}

